using System.Diagnostics;using System.Reflection;namespace BgCommon;/// <summary>/// 应用程序版本与元数据信息的辅助工具类./// </summary>public class VersionHelper{    /// <summary>    /// Initializes a new instance of the <see cref="VersionHelper"/> class.    /// </summary>    public VersionHelper()    {    }    /// <summary>    /// 获取当前入口程序集的版本号.    /// </summary>    /// <returns>返回格式为 "V" 加上文件版本号的字符串.</returns>    public static string GetVersion()    {        // 获取当前入口程序集，如果为空则后续无法获取路径        Assembly? entryAssembly = Assembly.GetEntryAssembly();        if (entryAssembly == null)        {            return "V0.0.0.0";        }        // 获取该程序集文件的详细版本信息        FileVersionInfo assemblyVersionInfo = FileVersionInfo.GetVersionInfo(entryAssembly.Location);        // 初始化框架版本名称变量        string frameworkVersionName = string.Empty;#if NET40        frameworkVersionName = ".NET Framework 4.0";#elif NET45        frameworkVersionName = ".NET Framework 4.5";#elif NET451        frameworkVersionName = ".NET Framework 4.5.1";#elif NET452        frameworkVersionName = ".NET Framework 4.5.2";#elif NET46        frameworkVersionName = ".NET Framework 4.6";#elif NET461        frameworkVersionName = ".NET Framework 4.6.1";#elif NET462        frameworkVersionName = ".NET Framework 4.6.2";#elif NET47        frameworkVersionName = ".NET Framework 4.7";#elif NET471        frameworkVersionName = ".NET Framework 4.7.1";#elif NET472        frameworkVersionName = ".NET Framework 4.7.2";#elif NET48        frameworkVersionName = ".NET Framework 4.8";#elif NET481        frameworkVersionName = ".NET Framework 4.8.1";#elif NET5_0        frameworkVersionName = ".NET 5.0";#elif NET6_0        frameworkVersionName = ".NET 6.0";#elif NET7_0        frameworkVersionName = ".NET 7.0";#elif NET8_0        frameworkVersionName = ".NET 8.0";#elif NETCOREAPP3_0        frameworkVersionName = ".NET CORE 3.0";#elif NETCOREAPP3_1        frameworkVersionName = ".NET CORE 3.1";#endif        // 返回合并后的版本信息字符串.        return $"V{assemblyVersionInfo.FileVersion}";    }    /// <summary>    /// 获取当前入口程序集的版权声明信息.    /// </summary>    /// <returns>版权声明字符串.</returns>    public static string GetCopyright()    {        // 获取入口程序集引用        Assembly? entryAssembly = Assembly.GetEntryAssembly();        if (entryAssembly == null)        {            return string.Empty;        }        // 提取并返回法律版权信息字段.        return FileVersionInfo.GetVersionInfo(entryAssembly.Location).LegalCopyright ?? "Copy Right @ 2026";    }}